
"use client";
import { useState, useEffect } from "react";
import Image from 'next/image';
import Link from 'next/link';
import {
  Home,
  FileText,
  CalendarCheck,
  FlaskConical,
  History,
  Settings,
  Library,
  LogOut,
  Users,
  PlusCircle
} from 'lucide-react';
import { usePathname } from "next/navigation";
import { useAuth } from "@/contexts/AuthContext";
import { addAuditLogAction, getLabsAction, getPcsAction, addLabAction } from "@/app/actions/dbActions";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { toast } from "sonner";
import { Lab, Pc } from "@/utils/storage";

const AdminSidebar = () => {
    const { user, logout } = useAuth();
    const pathname = usePathname();

    const handleLogout = async () => {
        if(user) {
            await addAuditLogAction({ userId: user.id, userName: user.name, action: 'logout' });
        }
        logout();
    };

    const sidebarNavItems = [
        { title: 'Dashboard', icon: Home, href: '/dashboard' },
        { title: 'User Management', icon: Users, href: '/admin/users' },
        { title: 'Request Management', icon: FileText, href: '/admin/requests' },
        { title: 'Attendance Report', icon: CalendarCheck, href: '/admin/reports' },
        { title: 'LAB Management', icon: FlaskConical, href: '/admin/labs' },
        { title: 'Library', icon: Library, href: '/admin/library' },
        { title: 'Audit Log', icon: History, href: '/admin/audit' },
        { title: 'System Settings', icon: Settings, href: '/admin/settings' },
    ];

    return (
        <aside className="w-64 bg-white p-5 flex flex-col border-r">
            <div className="text-center mb-6 mt-2">
                <Link href="/profile">
                    <div className="w-16 h-16 rounded-md bg-primary text-white flex items-center justify-center mx-auto mb-3 cursor-pointer">
                        <span className="text-2xl font-bold">{user?.name?.charAt(0) || 'A'}</span>
                    </div>
                </Link>
                <h3 className="font-semibold text-gray-800">Administrator</h3>
                <p className="text-sm text-muted-foreground">{user?.name}</p>
            </div>

            <nav className="flex-grow space-y-2">
                {sidebarNavItems.map((item) => {
                    const isActive = pathname === item.href;
                    return (
                        <Link key={item.title} href={item.href} passHref>
                            <Button
                                variant={isActive ? 'default' : 'ghost'}
                                className={`w-full justify-start gap-3 text-base font-medium ${isActive ? 'text-white' : 'text-gray-600 hover:text-primary hover:bg-primary/5'}`}
                                style={isActive ? { backgroundColor: '#E30613' } : {}}
                            >
                                <item.icon className={`w-5 h-5 ${isActive ? 'text-white' : 'text-gray-400 group-hover:text-primary'}`} />
                                {item.title}
                            </Button>
                        </Link>
                    )
                })}
            </nav>
            
            <div className="mt-auto">
                <Button onClick={handleLogout} variant="ghost" className="w-full justify-start gap-3 text-base font-medium text-red-500 hover:text-red-700 hover:bg-red-50">
                    <LogOut className="w-5 h-5" />
                    Logout
                </Button>
            </div>
        </aside>
    );
}

export default function LabManagementPage() {
    const [labs, setLabs] = useState<Lab[]>([]);
    const [pcs, setPcs] = useState<Pc[]>([]);
    const [newLabName, setNewLabName] = useState('');
    const [newLabCapacity, setNewLabCapacity] = useState('');

    useEffect(() => {
        fetchData();
    }, []);

    const fetchData = async () => {
        setLabs(await getLabsAction());
        setPcs(await getPcsAction());
    };

    const handleAddLab = async (e: React.FormEvent) => {
        e.preventDefault();
        if (!newLabName || !newLabCapacity) {
            toast.error("Please provide lab name and capacity.");
            return;
        }
        await addLabAction({
            id: `LAB-${Date.now()}`,
            name: newLabName,
            capacity: parseInt(newLabCapacity, 10),
        });
        toast.success("Lab and its PCs have been added successfully.");
        setNewLabName('');
        setNewLabCapacity('');
        fetchData();
    };
    
    return (
        <div className="min-h-screen bg-gray-50 flex flex-col">
            <header className="bg-primary shadow-lg sticky top-0 z-20">
                <div className="mx-auto px-8 h-16 flex items-center">
                    <Image src="/logo.png" alt="AMA Student Portal" width={150} height={38} priority />
                </div>
            </header>
            <div className="flex flex-1">
                <AdminSidebar />
                <main className="flex-1 p-8 overflow-y-auto">
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
                        <div className="lg:col-span-1">
                            <Card>
                                <CardHeader>
                                    <CardTitle>Add New LAB</CardTitle>
                                </CardHeader>
                                <CardContent>
                                    <form onSubmit={handleAddLab} className="space-y-4">
                                        <div className="space-y-2">
                                            <Label htmlFor="labName">LAB Name</Label>
                                            <Input id="labName" value={newLabName} onChange={e => setNewLabName(e.target.value)} placeholder="e.g., Computer Lab 1"/>
                                        </div>
                                        <div className="space-y-2">
                                            <Label htmlFor="labCapacity">Capacity</Label>
                                            <Input id="labCapacity" type="number" value={newLabCapacity} onChange={e => setNewLabCapacity(e.target.value)} placeholder="e.g., 30"/>
                                        </div>
                                        <Button type="submit" className="w-full bg-primary hover:bg-primary/90 text-white">
                                            <PlusCircle className="mr-2 h-4 w-4"/> Add LAB
                                        </Button>
                                    </form>
                                </CardContent>
                            </Card>
                        </div>
                        <div className="lg:col-span-2">
                            <Card>
                                <CardHeader>
                                    <CardTitle>Available LABs</CardTitle>
                                </CardHeader>
                                <CardContent className="space-y-6">
                                    {labs.map(lab => (
                                        <div key={lab.id} className="border p-4 rounded-lg">
                                            <h3 className="font-bold text-lg">{lab.name} (Capacity: {lab.capacity})</h3>
                                            <div className="pl-4 mt-4">
                                                <h4 className="font-semibold">PCs in this lab:</h4>
                                                <ul className="list-disc pl-5 mt-2 text-sm">
                                                    {pcs.filter(pc => pc.labId === lab.id).map(pc => (
                                                        <li key={pc.id}>PC #{pc.pcNumber} - <span className="capitalize text-muted-foreground">{pc.status}</span></li>
                                                    ))}
                                                </ul>
                                                {pcs.filter(pc => pc.labId === lab.id).length === 0 && (
                                                    <p className="text-sm text-muted-foreground italic">No PCs added yet.</p>
                                                )}
                                            </div>
                                        </div>
                                    ))}
                                    {labs.length === 0 && <p className="text-muted-foreground text-center">No LABs configured yet.</p>}
                                </CardContent>
                            </Card>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}
